import java.sql.Connection;
  import java.sql.DriverManager;
  import java.sql.PreparedStatement;
  import java.sql.SQLException;
  import java.sql.Types;
  import java.util.List;
  import sailpoint.api.SailPointContext;
  import sailpoint.connector.JDBCConnector;
  import sailpoint.object.Application;
  import sailpoint.object.ProvisioningPlan;
  import sailpoint.object.ProvisioningPlan.AccountRequest;
  import sailpoint.object.ProvisioningPlan.AttributeRequest;
  import sailpoint.object.ProvisioningPlan.PermissionRequest;
  import sailpoint.object.ProvisioningPlan.Operation;

  import java.text.SimpleDateFormat;
  import sailpoint.object.ProvisioningResult;
  import sailpoint.object.Schema;
  import sailpoint.tools.xml.XMLObjectFactory;
  import org.apache.commons.logging.LogFactory;
  import org.apache.commons.logging.Log;



  String MIDAS_VIEW_NAME = "CSQLV.MIDAS_SAILPOINT_TST_VIEW";

  public Object getAttributeRequestValue(AccountRequest acctReq, String attribute) {
    if (acctReq != null) {
      AttributeRequest attrReq = acctReq.getAttributeRequest(attribute);
      if (attrReq != null) {
        return attrReq.getValue();
      }
    }
    return null;
  }
  public ProvisioningPlan.Operation getAttributeRequestOp(AccountRequest acctReq, String attribute) {
    if (acctReq != null) {
      AttributeRequest attrReq = acctReq.getAttributeRequest(attribute);
      if (attrReq != null) {
        return attrReq.getOp();
      }
    }
    return null;
  }
  ProvisioningResult result = new ProvisioningResult();
  if (plan != null) {
    List accounts = plan.getAccountRequests();
    if ((accounts != null) && (accounts.size() > 0)) {
      for (AccountRequest account: accounts) {
        try {
          if (AccountRequest.Operation.Create.equals(account.getOperation())) {
            // Not supported.
          } else if (AccountRequest.Operation.Delete.equals(account.getOperation())) {
            // Not supported.
          } else if (AccountRequest.Operation.Modify.equals(account.getOperation())) {

            for (AttributeRequest attributeRequest : account.getAttributeRequests()) {
              String attribute = attributeRequest.getName();
              if (ProvisioningPlan.Operation.Set.equals(getAttributeRequestOp(account, attribute))) {
                Object newValue = getAttributeRequestValue(account, attribute);
                if (newValue instanceof String) {
                  PreparedStatement statement = connection.prepareStatement("update "+MIDAS_VIEW_NAME+" set "+attribute+" = "+newValue+" where NPI_if_applicable = ?");
                  statement.setString(1, (String) account.getNativeIdentity());
                  statement.executeUpdate();
                  statement.close();
                }
              }
            }

            if (ProvisioningPlan.Operation.Remove.equals(getAttributeRequestOp(account, "Specialty_Name"))) {
              Object specialtyNames = getAttributeRequestValue(account, "Specialty_Name");
              if (specialtyNames instanceof String) {
                PreparedStatement statement = connection.prepareStatement("delete from "+MIDAS_VIEW_NAME+" where NPI_if_applicable = ? and Specialty_Name = ?");
                statement.setString(1, (String) account.getNativeIdentity());
                statement.setString(2, specialtyNames);
                statement.executeUpdate();
                statement.close();
              } else if (specialtyNames instanceof List) {
                for (String eachSpecialty : specialtyNames) {
                  PreparedStatement statement = connection.prepareStatement("delete from "+MIDAS_VIEW_NAME+" where NPI_if_applicable = ? and Specialty_Name = ?");
                  statement.setString(1, (String) account.getNativeIdentity());
                  statement.setString(2, eachSpecialty);
                  statement.executeUpdate();
                  statement.close();  
                }
              }
            }
          } else if (AccountRequest.Operation.Disable.equals(account.getOperation())) {
            Date today = new Date();
            SimpleDateFormat sdf = new SimpleDateFormat("MM/dd/yyyy hh:mm:ss aa zzz");
            PreparedStatement statement = connection.prepareStatement("update "+MIDAS_VIEW_NAME+" set Next_Reappointment_Date='"+sdf.format(today)+"' where NPI_if_applicable= ?");
            statement.setString(1, (String) account.getNativeIdentity());
            statement.executeUpdate();
            result.setStatus(ProvisioningResult.STATUS_COMMITTED);
          } else if (AccountRequest.Operation.Enable.equals(account.getOperation())) {
            // Not supported.
          } else if (AccountRequest.Operation.Lock.equals(account.getOperation())) {
            // Not supported.
          } else if (AccountRequest.Operation.Unlock.equals(account.getOperation())) {
            // Not supported.
          } else {
            // Unknown operation!
          }
        } catch (SQLException e) {
          //_log.error(e);
          result.setStatus(ProvisioningResult.STATUS_FAILED);
          result.addError(e);
        }
      }
    }
  }
  return result;
